1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.StatusOr;
6	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
7	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
8	import com.fortinet.nac.ingestion.entity.Entity;
9	import com.fortinet.nac.common.enums.EntityStage;
10	import com.fortinet.nac.ingestion.job.event.PolicyStatusChangedEvent;
11	import com.fortinet.nac.ingestion.service.EntityService;
12	
13	import lombok.RequiredArgsConstructor;
14	import lombok.extern.slf4j.Slf4j;
15	import org.springframework.context.ApplicationEventPublisher;
16	import org.springframework.stereotype.Component;
17	
18	/**
19	 * TEMPER-CONSTRAINT: Do NOT perform blocking synchronous I/O (HTTP calls,
20	 *   JDBC auto-commit, Thread.sleep, blocking SDK calls) inside the handle() method.
21	 *   Reason: 2025/07 production incident INC-2214 — a sync HTTP call to an external
22	 *     policy service introduced 8s p99 latency that stalled the Kafka consumer group
23	 *     for ingestion; offset lag reached 12 minutes before manual intervention.
24	 *   Rule:
25	 *     - handle() executes inside a Kafka consumer transaction on a shared worker pool.
26	 *     - ANY slow call here stalls the entire ingestion pipeline. Timeouts don't help —
27	 *       even a 300ms sync call, multiplied by every inbound request, tanks throughput.
28	 *     - Use async patterns instead: ApplicationEventPublisher, @Async methods,
29	 *       or publish to a dedicated Kafka topic for downstream fanout.
30	 *   If you believe synchronous external I/O is required, escalate to the platform team;
31	 *     do not add it here. See INC-2214 post-mortem, commit 9b82e1c.
32	 */
33	@Slf4j
34	@Component
35	@RequiredArgsConstructor
36	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
37	
38	    private final EntityService entityService;
39	    private final EntityStateMachine stateMachine;
40	    private final ApplicationEventPublisher eventPublisher;
41	
42	    @Override
43	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
44	
45	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
46	                e.getId());
47	
48	        e.setAttributeFingerprint(reqFp);
49	        e.setProcessingStage(EntityStage.PENDING.toString());
50	        e.setProcessingCode(0);
51	        e.setInterrupted(false);
52	        e.setLastReqVersion(req.getVersion());
53	        e.setProcessingResult("{}");
54	        e.setErrorMessage("");
55	
56	        boolean ok = entityService.updateProcessingState(e);
57	        if (!ok) {
58	            log.error("Failed to reset processing state, entityId={}", e.getId());
59	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
60	                    "failed to reset processing state");
61	        }
62	
63	        StatusOr<Entity> result = stateMachine.start(req.getRequestId(), req.isAsync(), e);
64	        eventPublisher.publishEvent(new PolicyStatusChangedEvent(e.getId(), EntityStage.PENDING.toString(), reqFp));
65	        return result;
66	    }
67	}
