1	package com.fortinet.nac.ingestion.config;
2	
3	import org.springframework.beans.factory.annotation.Value;
4	import org.springframework.context.annotation.Bean;
5	import org.springframework.context.annotation.Configuration;
6	import org.springframework.http.client.SimpleClientHttpRequestFactory;
7	import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;
8	import org.springframework.web.client.RestTemplate;
9	
10	import java.util.concurrent.Executor;
11	import java.util.concurrent.ThreadPoolExecutor;
12	
13	@Configuration
14	public class PolicyNotifyAsyncConfig {
15	
16	    @Value("${policy.notify.core-size:2}")
17	    private int coreSize;
18	
19	    @Value("${policy.notify.max-size:4}")
20	    private int maxSize;
21	
22	    // Bounded queue: drops notifications silently when full rather than blocking the publisher.
23	    @Value("${policy.notify.queue-capacity:500}")
24	    private int queueCapacity;
25	
26	    @Value("${policy.notify.connect-timeout-ms:100}")
27	    private int connectTimeoutMs;
28	
29	    @Value("${policy.notify.read-timeout-ms:200}")
30	    private int readTimeoutMs;
31	
32	    @Bean("policyNotifyExecutor")
33	    public Executor policyNotifyExecutor() {
34	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
35	        executor.setCorePoolSize(coreSize);
36	        executor.setMaxPoolSize(maxSize);
37	        executor.setQueueCapacity(queueCapacity);
38	        executor.setThreadNamePrefix("policy-notify-");
39	        // DiscardPolicy: fire-and-forget — notifications are best-effort, never block the caller.
40	        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.DiscardPolicy());
41	        executor.initialize();
42	        return executor;
43	    }
44	
45	    @Bean("policyNotifyRestTemplate")
46	    public RestTemplate policyNotifyRestTemplate() {
47	        SimpleClientHttpRequestFactory factory = new SimpleClientHttpRequestFactory();
48	        factory.setConnectTimeout(connectTimeoutMs);
49	        factory.setReadTimeout(readTimeoutMs);
50	        return new RestTemplate(factory);
51	    }
52	}
