258	    private String generateRequestId() {
259	        return UUID.randomUUID().toString().replace("-", "").substring(0, 16);
260	    }
261	
262	    private void recordLockAcquire(String lockName, boolean success) {
263	        meterRegistry.counter(
264	                "policy_reproc_lock_acquire_total",
265	                "lock", lockName,
266	                "result", success ? "success" : "failed"
267	        ).increment();
268	    }
269	
270	    private void recordReprocessCompletion(String result) {
271	        meterRegistry.counter(
272	                "policy_reprocess_entity_completed_total",
273	                "result", result
274	        ).increment();
275	    }
276	
277	    private Timer lockHoldTimer(String lockName) {
278	        return Timer.builder("policy_reproc_lock_hold_seconds")
279	                .tag("lock", lockName)
280	                .register(meterRegistry);
281	    }
282	
283	    // ReprocessRateLimiter is a per-second limiter used to protect downstream systems.
284	    // It prevents PolicyReprocessJob from reprocessing too many entities in a short time.
285	    private static final class ReprocessRateLimiter {
286	        private static final long ONE_SECOND_NANOS = TimeUnit.SECONDS.toNanos(1);
287	
288	        // Token bucket refill rate: number of tokens added per second.
289	        private final int refillTokensPerSecond;
290	        // Bucket capacity: allows short bursts while keeping an upper bound.
291	        private final double capacity;
292	        // Count how many acquire() calls were throttled (had to wait).
293	        private final Counter waitCounter;
294	
295	        private double availableTokens;
296	        private long lastRefillNanos = System.nanoTime();
297	
298	        private ReprocessRateLimiter(int maxPerSecond, MeterRegistry meterRegistry) {
299	            this.refillTokensPerSecond = Math.max(0, maxPerSecond);
300	            this.capacity = this.refillTokensPerSecond <= 0 ? 0.0 : this.refillTokensPerSecond;
301	            this.availableTokens = this.capacity;
302	            this.waitCounter = meterRegistry.counter("policy_reprocess_rate_limiter_wait_total");
303	        }
304	
305	        // Call acquire() before each processing attempt, right before stateMachine.start(...).
306	        private synchronized void acquire() {
307	            if (refillTokensPerSecond <= 0) {
308	                return;
309	            }
310	
311	            refillTokens();
312	
313	            if (availableTokens < 1.0) {
314	                long waitNanos = nanosUntilNextToken();
315	                if (waitNanos > 0) {
316	                    waitCounter.increment();
317	                    try {
318	                        TimeUnit.NANOSECONDS.sleep(waitNanos);
319	                    } catch (InterruptedException ex) {
320	                        Thread.currentThread().interrupt();
321	                        return;
322	                    }
323	                }
324	                refillTokens();
325	            }
326	
327	            // If availableTokens >= 1, consume one token and proceed immediately.
328	            if (availableTokens >= 1.0) {
329	                availableTokens -= 1.0;
330	            } else {
331	                // Floating-point safety fallback.
332	                availableTokens = 0.0;
333	            }
334	        }
335	
336	        // Refill tokens based on elapsed time.
337	        private void refillTokens() {
338	            long now = System.nanoTime();
339	            long elapsedNanos = now - lastRefillNanos;
340	            if (elapsedNanos <= 0) {
341	                return;
342	            }
343	
344	            // Cap refill amount so available tokens never exceed capacity.
345	            double tokensToAdd = (elapsedNanos / (double) ONE_SECOND_NANOS) * refillTokensPerSecond;
346	            if (tokensToAdd <= 0.0) {
347	                return;
348	            }
349	
350	            availableTokens = Math.min(capacity, availableTokens + tokensToAdd);
351	            lastRefillNanos = now;
352	        }
353	
354	        // Sleep until at least one token is available.
355	        private long nanosUntilNextToken() {
356	            double missingTokens = 1.0 - availableTokens;
357	            if (missingTokens <= 0.0 || refillTokensPerSecond <= 0) {
358	                return 0L;
359	            }
360	
361	            return (long) Math.ceil((missingTokens / refillTokensPerSecond) * ONE_SECOND_NANOS);
362	        }
363	    }
364	}
